package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }
import ssg.js.compress.{ ToplevelConfig }

final class CompressIssue1261Suite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // pure_function_calls
  // =========================================================================
  test("pure_function_calls".fail) {
    assertCompresses(
      input = """// pure top-level IIFE will be dropped
        // @__PURE__ - comment
        (function() {
            console.log("iife0");
        })();

        // pure top-level IIFE assigned to unreferenced var will not be dropped
        var iife1 = /*@__PURE__*/(function() {
            console.log("iife1");
            function iife1() {}
            return iife1;
        })();

        (function(){
            // pure IIFE in function scope assigned to unreferenced var will be dropped
            var iife2 = /*#__PURE__*/(function() {
                console.log("iife2");
                function iife2() {}
                return iife2;
            })();
        })();

        // comment #__PURE__ comment
        bar(), baz(), quux();
        a.b(), /* @__PURE__ */ c.d.e(), f.g()""".stripMargin.trim,
      expected = """var iife1 = function() {
            console.log("iife1");
            function iife1() {}
            return iife1;
        }();

        baz(), quux();
        a.b(), f.g()""".stripMargin.trim,
      options = AllOff.copy(
        booleans = true,
        comparisons = true,
        conditionals = true,
        evaluate = true,
        ifReturn = true,
        joinVars = true,
        negateIife = true,
        sideEffects = true,
        unused = true
      )
    )
  }

  // =========================================================================
  // pure_function_calls_toplevel
  // =========================================================================
  test("pure_function_calls_toplevel".fail) {
    assertCompresses(
      input = """// pure top-level IIFE will be dropped
        // @__PURE__ - comment
        (function() {
            console.log("iife0");
        })();

        // pure top-level IIFE assigned to unreferenced var will be dropped
        var iife1 = /*@__PURE__*/(function() {
            console.log("iife1");
            function iife1() {}
            return iife1;
        })();

        (function(){
            // pure IIFE in function scope assigned to unreferenced var will be dropped
            var iife2 = /*#__PURE__*/(function() {
                console.log("iife2");
                function iife2() {}
                return iife2;
            })();
        })();

        // pure top-level calls will be dropped regardless of the leading comments position
        var MyClass = /*#__PURE__*//*@class*/(function(){
            function MyClass() {}
            MyClass.prototype.method = function() {};
            return MyClass""".stripMargin.trim,
      expected = """baz(), quux();
        a.b(), f.g()""".stripMargin.trim,
      options = AllOff.copy(
        booleans = true,
        comparisons = true,
        conditionals = true,
        evaluate = true,
        ifReturn = true,
        joinVars = true,
        negateIife = true,
        sideEffects = true,
        toplevel = ToplevelConfig(funcs = true, vars = true),
        unused = true
      )
    )
  }

